public class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode(int x) { val = x; }
}

public int longestConsecutiveSequence(TreeNode root, int[] longestPath) {
    if (root == null) {
        return 0;
    }
    int left = longestConsecutiveSequence(root.left, longestPath);
    int right = longestConsecutiveSequence(root.right, longestPath);
    int currPath = 1;
    if (root.left != null && root.left.val == root.val + 1) {
        currPath = Math.max(currPath, left + 1);
    }
    if (root.right != null && root.right.val == root.val + 1) {
        currPath = Math.max(currPath, right + 1);
    }
    longestPath[0] = Math.max(longestPath[0], currPath);
    return currPath;
}

public int longestConsecutive(TreeNode root) {
    int[] longestPath = new int[1];
    longestConsecutiveSequence(root, longestPath);
    return longestPath[0];
}
```


